import { Navigate, Outlet } from 'react-router-dom';

function ProtectedRoute() {
  const { user } = useAuth();  // seu hook/context de auth

  if (!user) {
    return <Navigate to="/login" replace />;
  }

  return <Outlet />;  // renderiza as rotas filhas normalmente
}

// Uso nas rotas:
const router = createBrowserRouter([
  // Rotas públicas
  { path: '/login', element: <Login /> },
  { path: '/register', element: <Register /> },

  // Rotas protegidas
  {
    element: <ProtectedRoute />,
    children: [
      { path: '/dashboard', element: <Dashboard /> },
      { path: '/profile', element: <Profile /> },
      { path: '/settings', element: <Settings /> },
    ],
  },
]);

// Redirect simples
<Navigate to="/login" />

// Com replace (não empilha no histórico)
<Navigate to="/login" replace />

// Passando state (ex: 'de onde veio' para redirect pós-login)
<Navigate to="/login" state={{ from: location.pathname }} replace />

import { useNavigate } from 'react-router-dom';

function LoginForm() {
  const navigate = useNavigate();

  const handleLogin = async (data) => {
    await login(data);
    navigate('/dashboard');          // vai para /dashboard
    // navigate('/dashboard', { replace: true });  // sem voltar
    // navigate(-1);                  // volta uma página
    // navigate(-2);                  // volta duas páginas
  };

  return <form onSubmit={handleLogin}>...</form>;
}

function LogoutButton() {
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login', { replace: true });
  };

  return <button onClick={handleLogout}>Sair</button>;
}

// No ProtectedRoute: salva de onde veio
<Navigate to="/login" state={{ from: location.pathname }} replace />

// No Login: redireciona de volta
function Login() {
  const navigate = useNavigate();
  const location = useLocation();
  const from = location.state?.from || '/dashboard';

  const handleLogin = async () => {
    await doLogin();
    navigate(from, { replace: true });
  };
}

