import { useState } from 'react';
import {
  createBrowserRouter,
  RouterProvider,
  Navigate,
  Outlet,
  Link,
  useNavigate,
} from 'react-router-dom';

let _isLoggedIn = false;
function useAuth() {
  const [loggedIn, setLoggedIn] = useState(_isLoggedIn);
  return {
    isLoggedIn: loggedIn,
    login: () => { _isLoggedIn = true; setLoggedIn(true); },
    logout: () => { _isLoggedIn = false; setLoggedIn(false); },
  };
}

function ProtectedRoute() {
  const { isLoggedIn } = useAuth();
  if (!isLoggedIn) return <Navigate to="/login" replace />;
  return <Outlet />;
}

function Login() {
  const { login } = useAuth();
  const navigate = useNavigate();
  return (
    <div className="p-4">
      <h1 className="text-xl font-bold">Login</h1>
      <button
        onClick={() => { login(); navigate('/dashboard'); }}
        className="mt-4 rounded bg-blue-600 px-4 py-2 text-white"
      >
        Entrar
      </button>
    </div>
  );
}

function Dashboard() {
  const { logout } = useAuth();
  const navigate = useNavigate();
  return (
    <div className="p-4">
      <h1 className="text-xl font-bold">Dashboard</h1>
      <Link to="/profile" className="text-blue-500">Ver perfil</Link>
      <button
        onClick={() => { logout(); navigate('/login', { replace: true }); }}
        className="ml-4 rounded bg-red-600 px-4 py-2 text-white"
      >
        Sair
      </button>
    </div>
  );
}

function Profile() {
  return (
    <div className="p-4">
      <h1 className="text-xl font-bold">Perfil</h1>
      <Link to="/dashboard" className="text-blue-500">Voltar ao Dashboard</Link>
    </div>
  );
}

const router = createBrowserRouter([
  { path: '/login', element: <Login /> },
  {
    element: <ProtectedRoute />,
    children: [
      { path: '/dashboard', element: <Dashboard /> },
      { path: '/profile', element: <Profile /> },
    ],
  },
]);

export default function App() {
  return <RouterProvider router={router} />;
}
